export function createLargeMarkdownPreviewFixture(repeatCount = 180): string {
  const repeatedSections = Array.from({ length: repeatCount }, (_item, index) =>
    [
      `## Generated Section ${index + 1}`,
      "",
      `Generated paragraph ${index + 1} ${E2E_MARKDOWN_PREVIEW_ENGINE_PREFIX}`,
      "",
      "| Column | Value |",
      "| --- | --- |",
      `| generated-table-${index + 1} | ${index + 1} |`,
      "",
      "```ts",
      `const generatedCode${index + 1} = ${index + 1};`,
      "```",
      "",
    ].join("\n"),
  );
  return [
    markdownPreviewRendererParityFixture,
    "",
    ...repeatedSections,
    "## E2E Tail Section",
    "",
    "Tail heading visible",
    "",
    "tail-search-target",
  ].join("\n");
}

